```class Solution {
public:
    long long minimumCost(string s) {
        int n = s.size();
        vector<int> cnt0(n + 1), cnt1(n + 1);
        for (int i = 0; i < n; i++) {
            cnt0[i + 1] = cnt0[i] + (s[i] == '0');
            cnt1[i + 1] = cnt1[i] + (s[i] == '1');
        }
        long long res = LLONG_MAX;
        for (int i = 0; i < n; i++) {
            res = min(res, i + 1 - cnt0[i] + cnt1[n] - cnt1[i]);
            res = min(res, (n - i) - cnt1[i] + cnt0[n] - cnt0[i]);
        }
        return res;
    }
};
